mapper.select:
SELECT o.id, o.order_no, o.customer_id, o.warehouse_id, c.name AS customer_name, o.order_date, o.total_amount, o.discount_amount, o.final_amount, o.status, o.remark, o.created_by, o.created_at, o.updated_at, o.confirm_time, o.deliver_time FROM sal_order o LEFT JOIN customer c ON o.customer_id = c.id
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.customer_id = #{customerId}
AND o.status = #{status}
AND c.name LIKE CONCAT('%', #{customerName}, '%')
ORDER BY o.created_at DESC

mapper.update:
UPDATE sal_order
customer_id = #{customerId}, warehouse_id = #{warehouseId}, order_date = #{orderDate}, total_amount = #{totalAmount}, discount_amount = #{discountAmount}, final_amount = #{finalAmount}, status = #{status}, remark = #{remark}, confirm_time = #{confirmTime}, deliver_time = #{deliverTime}, updated_at = NOW()
WHERE id = #{id}
